// Page de chat — interface principale du chatbot
import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import styles from './Chat.module.css';

// Exemples de phrases cliquables
const EXAMPLES = [
  'azul, matta tgim ?',
  'acu t-isem-ik ?',
  'manis d-tusiḍ ?',
  'suqel-iyi awal "tafukt"',
  'tanmmirt !',
];

// Étapes du pipeline affichées dans la barre
const PIPE_STEPS = [
  'Entrée',
  'Translittération',
  'Détection intention',
  'Génération Mistral',
  'Réponse',
];

export default function Chat() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  // Liste des messages : { role: 'user'|'bot', text, intent?, time }
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [activeStep, setActiveStep] = useState(-1); // -1 = inactif
  const [doneSteps, setDoneSteps] = useState([]);

  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  // Scroll automatique vers le bas après chaque message
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Auto-resize du textarea
  const handleInputChange = e => {
    setInput(e.target.value);
    const el = textareaRef.current;
    el.style.height = 'auto';
    el.style.height = Math.min(el.scrollHeight, 140) + 'px';
  };

  // Clic sur un exemple → remplit le champ
  const useExample = text => {
    setInput(text);
    textareaRef.current?.focus();
  };

  // Animation du pipeline : allume chaque étape successivement
  const animatePipeline = async () => {
    setDoneSteps([]);
    for (let i = 0; i < PIPE_STEPS.length - 1; i++) {
      setActiveStep(i);
      await new Promise(r => setTimeout(r, 400));
      setDoneSteps(prev => [...prev, i]);
    }
    setActiveStep(PIPE_STEPS.length - 1);
  };

  const finishPipeline = () => {
    setDoneSteps(PIPE_STEPS.map((_, i) => i));
    setActiveStep(-1);
    setTimeout(() => { setDoneSteps([]); setActiveStep(-1); }, 2500);
  };

  // ── Envoi d'un message ──
  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading) return;

    // Ajouter le message utilisateur à la liste
    const userMsg = { role: 'user', text, time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }) };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';

    setLoading(true);
    animatePipeline();

    try {
      // Appel au backend Python
      const res = await axios.post('/chat', { message: text });
      const { response, intent, normalized, confidence } = res.data;

      const botMsg = {
        role: 'bot',
        text: response,
        intent,
        normalized,
        confidence,
        time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
      };
      setMessages(prev => [...prev, botMsg]);
      finishPipeline();
    } catch (err) {
      const errMsg = {
        role: 'bot',
        text: 'Γalaṭ : ur yeẓẓi ara backend. Senqed aselkim-ik.',
        intent: 'error',
        time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
      };
      setMessages(prev => [...prev, errMsg]);
      setDoneSteps([]); setActiveStep(-1);
    } finally {
      setLoading(false);
    }
  };

  // Entrée = envoyer, Shift+Entrée = nouvelle ligne
  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  // Déconnexion
  const handleLogout = () => { logout(); navigate('/'); };

  return (
    <div className={styles.page}>
      {/* ── Sidebar ── */}
      <aside className={styles.sidebar}>
        <div className={styles.sidebarLogo}>
          <div className={styles.logoMark}>ⴰ</div>
          <span className={styles.logoText}>AWAL GPT</span>
        </div>

        {/* Bouton nouvelle conversation */}
        <button className={styles.newChat} onClick={() => setMessages([])}>
          + Nouvelle conversation
        </button>

        {/* Exemples */}
        <div className={styles.sideSection}>
          <div className={styles.sideSectionTitle}>Exemples</div>
          {EXAMPLES.map((ex, i) => (
            <button key={i} className={styles.exampleBtn} onClick={() => useExample(ex)}>
              {ex}
            </button>
          ))}
        </div>

        {/* Infos utilisateur en bas */}
        <div className={styles.sideFooter}>
          <div className={styles.userInfo}>
            <div className={styles.userAvatar}>{user?.name?.[0]?.toUpperCase() || 'U'}</div>
            <div>
              <div className={styles.userName}>{user?.name}</div>
              <div className={styles.userEmail}>{user?.email}</div>
            </div>
          </div>
          <button className={styles.logoutBtn} onClick={handleLogout}>Déconnexion</button>
        </div>
      </aside>

      {/* ── Zone principale ── */}
      <main className={styles.main}>
        {/* Barre pipeline */}
        <div className={styles.pipeline}>
          {PIPE_STEPS.map((step, i) => (
            <React.Fragment key={i}>
              <div className={`${styles.pipeStep}
                ${activeStep === i ? styles.pipeActive : ''}
                ${doneSteps.includes(i) ? styles.pipeDone : ''}`}>
                <span className={styles.pipeDot} />
                {step}
              </div>
              {i < PIPE_STEPS.length - 1 && <span className={styles.pipeArrow}>→</span>}
            </React.Fragment>
          ))}
        </div>

        {/* Zone messages */}
        <div className={styles.messages}>
          {/* Message de bienvenue si aucun message */}
          {messages.length === 0 && (
            <div className={styles.welcome}>
              <div className={styles.welcomeIcon}>ⴰ</div>
              <h2 className={styles.welcomeTitle}>Azul ! Anwa k tgit ?</h2>
              <p className={styles.welcomeSub}>
                Chatbot Tamazight latin — Écrivez ci-dessous en Tamazight pour commencer.
              </p>
            </div>
          )}

          {/* Liste des messages */}
          {messages.map((msg, i) => (
            <div key={i} className={`${styles.msgRow} ${msg.role === 'user' ? styles.msgUser : styles.msgBot}`}>
              <div className={styles.msgAvatar}>
                {msg.role === 'user' ? user?.name?.[0]?.toUpperCase() || 'U' : 'ⴰ'}
              </div>
              <div className={styles.msgBody}>
                <div className={styles.msgBubble}>{msg.text}</div>
                <div className={styles.msgMeta}>
                  {/* Affiche l'intention détectée pour les messages bot */}
                  {msg.intent && msg.intent !== 'error' && msg.role === 'bot' && (
                    <span className={styles.intentTag}>{msg.intent}</span>
                  )}
                  <span className={styles.msgTime}>{msg.time}</span>
                </div>
              </div>
            </div>
          ))}

          {/* Indicateur de frappe pendant le chargement */}
          {loading && (
            <div className={`${styles.msgRow} ${styles.msgBot}`}>
              <div className={styles.msgAvatar}>ⴰ</div>
              <div className={styles.msgBody}>
                <div className={styles.typingBubble}>
                  <span className={styles.typingDot} />
                  <span className={styles.typingDot} />
                  <span className={styles.typingDot} />
                </div>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Zone de saisie */}
        <div className={styles.inputArea}>
          <div className={styles.inputWrap}>
            <textarea
              ref={textareaRef}
              className={styles.textarea}
              placeholder="Aru s tmazight (ex: azul, matta tgim ?)..."
              value={input}
              onChange={handleInputChange}
              onKeyDown={handleKeyDown}
              rows={1}
            />
            <button
              className={styles.sendBtn}
              onClick={sendMessage}
              disabled={loading || !input.trim()}
            >
              {/* Icône envoyer */}
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <line x1="22" y1="2" x2="11" y2="13" />
                <polygon points="22 2 15 22 11 13 2 9 22 2" />
              </svg>
            </button>
          </div>
          <p className={styles.inputHint}>Entrée pour envoyer · Shift+Entrée pour nouvelle ligne</p>
        </div>
      </main>
    </div>
  );
}
